<div class="zhaizhai-masonry zhaizhai-reading-detail">
<div class="shuoshuo-item zhaizhai-item ">
  <div class="zhaizhai-flip-card">
    <div class="zhaizhai-face zhaizhai-face-front container">
      <div class="zhaizhai-top">
        <div class="zhaizhai-tags"></div>
        <time class="zhaizhai-date">2026-04-03</time>
      </div>
      <div class="zhaizhai-content-wrap">
        <div class="zhaizhai-content">每个人都应该注意自己的思维特点，<br>把它看做世界上最特殊也最珍贵的花园。<br>每天浇水，<br>保持充足的阳光和爱心，<br>除去杂草，<br>专心地培育那些花儿们。<br>只要给予适当的照顾，<br>精神花园就会年复一年地茁壮成长，<br>最终它会拥有非凡气度的成熟思想。<br>你的精神花园里会长满鲜花、树木、灌木丛和藤蔓，<br>繁茂兴盛。<br>你将有勇气面对一切暴风雨，<br>获得最美妙的生活。</div>
        <div class="zhaizhai-source">—— 节选自《分心也有好人生》</div>
        <div class="zhaizhai-meta">
          <span></span>
        </div>
      </div>
    </div>
    <div class="zhaizhai-face zhaizhai-face-back container">
      <div class="zhaizhai-back-header"><span class="zhaizhai-back-title">思考卡片</span></div>
      <div class="zhaizhai-back-body"><section class="zhaizhai-back-section zhaizhai-back-empty">暂无 insight</section></div>
    </div>
  </div>
</div>
</div>

<script>
(() => {
  let flipSwitchTimer = null

  document.addEventListener('click', event => {
    if (event.target.closest('a')) return
    const card = event.target.closest('.zhaizhai-reading-detail .zhaizhai-flip-card')
    if (!card) return
    if (flipSwitchTimer) {
      clearTimeout(flipSwitchTimer)
      flipSwitchTimer = null
    }
    const container = card.closest('.zhaizhai-reading-detail')
    const cards = container ? container.querySelectorAll('.zhaizhai-flip-card.is-flipped') : []
    const isFlipped = card.classList.contains('is-flipped')

    cards.forEach(item => {
      if (item !== card) item.classList.remove('is-flipped')
    })

    if (isFlipped) {
      card.classList.remove('is-flipped')
    } else {
      const hasOtherFlipped = [...cards].some(item => item !== card)
      if (hasOtherFlipped) {
        // Close previous card first, then open target card for smoother switch.
        flipSwitchTimer = setTimeout(() => {
          card.classList.add('is-flipped')
          flipSwitchTimer = null
        }, 120)
      } else {
        card.classList.add('is-flipped')
      }
    }
  })
})()
</script>
